import React, { useState, useEffect } from 'react';
import { getApiBase } from '../utils/platform';
import { tokens } from '../styles/tokens';
import s from './ReleaseChecklistPage.module.css';

const COLORS = {
  bg: tokens.color.bg, surface: tokens.color.surface, border: tokens.color.border,
  textPrimary: tokens.color.text, textSecondary: tokens.color.textSecondary,
  green: tokens.color.green, red: tokens.color.red, amber: tokens.color.amber, blue: tokens.color.blue,
};

const CHECKLIST_ITEMS = [
  { id: 'tests', label: 'Tests passing' },
  { id: 'build', label: 'Build clean' },
  { id: 'security', label: 'Security scan' },
  { id: 'lint', label: 'Lint clean' },
  { id: 'migrations', label: 'DB migrations' },
  { id: 'api_contracts', label: 'API contracts validated' },
];

const ENVIRONMENTS = [
  { key: 'staging', label: 'Staging' },
  { key: 'canary', label: 'Canary' },
  { key: 'production', label: 'Production' },
];

const ROLLBACK_TRIGGERS = [
  { id: 'error_rate', label: 'Error Rate', threshold: '> 5%', unit: '%' },
  { id: 'latency_p99', label: 'Latency (p99)', threshold: '> 2s', unit: 'ms' },
  { id: 'health_checks', label: 'Health Check Failures', threshold: '> 0', unit: '' },
];

export default function ReleaseChecklistPage() {
  const [checked, setChecked] = useState({});
  const [healthData, setHealthData] = useState(null);
  const [deployData, setDeployData] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [showConfirm, setShowConfirm] = useState(false);

  useEffect(() => {
    let cancelled = false;
    async function fetchData() {
      setLoading(true);
      setError(null);
      try {
        const [healthRes, deployRes] = await Promise.allSettled([
          fetch(`${getApiBase()}/system/health`),
          fetch(`${getApiBase()}/deploy/status`),
        ]);

        if (!cancelled) {
          if (healthRes.status === 'fulfilled' && healthRes.value.ok) {
            setHealthData(await healthRes.value.json());
          }
          if (deployRes.status === 'fulfilled' && deployRes.value.ok) {
            setDeployData(await deployRes.value.json());
          }
        }
      } catch (err) {
        if (!cancelled) setError(err.message);
      } finally {
        if (!cancelled) setLoading(false);
      }
    }
    fetchData();
    return () => { cancelled = true; };
  }, []);

  const toggleCheck = (id) => {
    setChecked((prev) => ({ ...prev, [id]: !prev[id] }));
  };

  const allChecked = CHECKLIST_ITEMS.every((item) => checked[item.id]);

  const getEnvData = (key) => {
    if (!deployData) return null;
    return deployData[key] || deployData.environments?.[key] || null;
  };

  const getHealthColor = (status) => {
    if (!status) return COLORS.textSecondary;
    const str = String(status).toLowerCase();
    if (str === 'healthy' || str === 'ok' || str === 'up') return COLORS.green;
    if (str === 'degraded' || str === 'warning') return COLORS.amber;
    return COLORS.red;
  };

  const getRollbackValue = (id) => {
    if (!healthData) return '--';
    if (id === 'error_rate') return healthData.error_rate ?? healthData.errorRate ?? '--';
    if (id === 'latency_p99') return healthData.latency_p99 ?? healthData.latencyP99 ?? '--';
    if (id === 'health_checks') return healthData.health_failures ?? healthData.healthFailures ?? 0;
    return '--';
  };

  const getRollbackStatus = (id) => {
    const val = getRollbackValue(id);
    if (val === '--') return 'unknown';
    const num = parseFloat(val);
    if (isNaN(num)) return 'unknown';
    if (id === 'error_rate') return num > 5 ? 'critical' : num > 2 ? 'warning' : 'ok';
    if (id === 'latency_p99') return num > 2000 ? 'critical' : num > 1000 ? 'warning' : 'ok';
    if (id === 'health_checks') return num > 0 ? 'critical' : 'ok';
    return 'ok';
  };

  const rollbackStatusColor = (status) => {
    if (status === 'critical') return COLORS.red;
    if (status === 'warning') return COLORS.amber;
    if (status === 'ok') return COLORS.green;
    return COLORS.textSecondary;
  };

  return (
    <div className={s.page}>
      <div className={s.header}>
        <h1 className={s.title}>Release Checklist</h1>
        <p className={s.subtitle}>Pre-release validation, deploy status, and rollback monitoring</p>
      </div>

      {error && <div className={s.errorText}>Failed to load status data: {error}</div>}

      {/* Pre-Release Checklist */}
      <h2 className={s.sectionTitle}>Pre-Release Validation</h2>
      <div className={s.card}>
        {CHECKLIST_ITEMS.map((item) => (
          <div
            key={item.id}
            className={s.checkRow}
            onClick={() => toggleCheck(item.id)}
          >
            <div className={checked[item.id] ? s.checkboxChecked : s.checkboxUnchecked}>
              {checked[item.id] && (
                <svg width="12" height="12" viewBox="0 0 12 12" fill="none">
                  <path d="M2 6L5 9L10 3" stroke="#000" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" />
                </svg>
              )}
            </div>
            <span className={s.checkLabel}>{item.label}</span>
            <span className={checked[item.id] ? s.checkStatusPassed : s.checkStatusPending}>
              {checked[item.id] ? 'Passed' : 'Pending'}
            </span>
          </div>
        ))}
      </div>

      {/* Deploy Status */}
      <h2 className={s.sectionTitle}>Deploy Status</h2>
      {loading ? (
        <div className={s.loadingText}>Loading deploy status...</div>
      ) : (
        <div className={s.grid3}>
          {ENVIRONMENTS.map((env) => {
            const data = getEnvData(env.key);
            const health = data?.health || data?.status || (healthData && env.key === 'production' ? (healthData.status || 'unknown') : 'unknown');
            const version = data?.version || '--';
            const lastDeploy = data?.last_deploy || data?.lastDeploy || '--';
            const trafficPct = data?.traffic_pct ?? data?.trafficPct ?? null;
            const errorRate = data?.error_rate ?? data?.errorRate ?? null;

            return (
              <div key={env.key} className={s.card}>
                <div className={s.envHeader}>
                  <div className={s.statusDot} style={{ backgroundColor: getHealthColor(health) }} />
                  <span className={s.envLabel}>{env.label}</span>
                </div>
                <div className={s.envRow}>
                  <span className={s.envKey}>Version</span>
                  <span className={s.envValue}>{version}</span>
                </div>
                <div className={s.envRow}>
                  <span className={s.envKey}>Last Deploy</span>
                  <span className={s.envValue}>{lastDeploy}</span>
                </div>
                <div className={s.envRow}>
                  <span className={s.envKey}>Health</span>
                  <span className={s.envValue} style={{ color: getHealthColor(health) }}>
                    {String(health).charAt(0).toUpperCase() + String(health).slice(1)}
                  </span>
                </div>
                {env.key === 'canary' && trafficPct !== null && (
                  <div className={s.envRow}>
                    <span className={s.envKey}>Traffic</span>
                    <span className={s.envValue}>{trafficPct}%</span>
                  </div>
                )}
                {env.key === 'canary' && errorRate !== null && (
                  <div className={s.envRow}>
                    <span className={s.envKey}>Error Rate</span>
                    <span className={s.envValue} style={{ color: parseFloat(errorRate) > 5 ? COLORS.red : COLORS.green }}>
                      {errorRate}%
                    </span>
                  </div>
                )}
              </div>
            );
          })}
        </div>
      )}

      {/* Rollback Trigger Monitoring */}
      <h2 className={s.sectionTitle}>Rollback Trigger Monitoring</h2>
      {loading ? (
        <div className={s.loadingText}>Loading monitoring data...</div>
      ) : (
        <div className={s.grid3}>
          {ROLLBACK_TRIGGERS.map((trigger) => {
            const value = getRollbackValue(trigger.id);
            const status = getRollbackStatus(trigger.id);
            const color = rollbackStatusColor(status);

            return (
              <div key={trigger.id} className={s.monitorCard}>
                <span className={s.monitorLabel}>{trigger.label}</span>
                <span className={s.monitorValue} style={{ color }}>
                  {value}{value !== '--' ? trigger.unit : ''}
                </span>
                <span className={s.monitorThreshold}>
                  Auto-rollback: {trigger.threshold}
                </span>
                {status === 'critical' && (
                  <span className={s.thresholdExceeded}>
                    THRESHOLD EXCEEDED
                  </span>
                )}
              </div>
            );
          })}
        </div>
      )}

      {/* Deploy Button */}
      <button
        className={allChecked ? s.deployBtnEnabled : s.deployBtnDisabled}
        disabled={!allChecked}
        onClick={() => allChecked && setShowConfirm(true)}
      >
        {allChecked ? 'Deploy to Production' : `Complete checklist (${Object.values(checked).filter(Boolean).length}/${CHECKLIST_ITEMS.length})`}
      </button>

      {/* Confirmation Modal */}
      {showConfirm && (
        <div className={s.confirmOverlay} onClick={() => setShowConfirm(false)}>
          <div className={s.confirmBox} onClick={(e) => e.stopPropagation()}>
            <h3 className={s.confirmTitle}>Confirm Deployment</h3>
            <p className={s.confirmText}>
              All pre-release checks have passed. This will initiate a production deployment.
              Rollback triggers are active and will automatically revert if thresholds are exceeded.
            </p>
            <div className={s.confirmBtnRow}>
              <button className={s.confirmCancel} onClick={() => setShowConfirm(false)}>
                Cancel
              </button>
              <button className={s.confirmDeploy} onClick={() => setShowConfirm(false)}>
                Confirm Deploy
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
